import type * as SarvamAI from "../index.js";
/**
 * Response model for job status endpoint.
 */
export interface DocDigitizationJobStatusResponse {
    /** Job identifier (UUID) */
    job_id: string;
    /** Current job state */
    job_state: SarvamAI.DocDigitizationJobState;
    /** Job creation timestamp (ISO 8601) */
    created_at: string;
    /** Last update timestamp (ISO 8601) */
    updated_at: string;
    /** Storage backend type */
    storage_container_type: SarvamAI.StorageContainerType;
    /** Total input files (always 1) */
    total_files?: number | undefined;
    /** Files that completed successfully */
    successful_files_count?: number | undefined;
    /** Files that failed */
    failed_files_count?: number | undefined;
    /** Job-level error message */
    error_message?: string | undefined;
    /** Per-file processing details with page metrics */
    job_details?: SarvamAI.DocDigitizationJobDetail[] | undefined;
}
